select 
from discuss_post
where status != 2

    and user_id = #{userId}


    and category_id = #{categoryId}


    and category_id in

        #{cid}



    and exists (
        select 1
        from post_tag pt
        join tag t on pt.tag_id = t.id
        where pt.post_id = discuss_post.id
          and t.name = #{tag}
    )


    order by type desc, create_time desc


    order by type desc, score desc, create_time desc

limit #{offset}, #{limit}

select 
from discuss_post
where status != 2
  and id > #{afterId}
order by id asc
limit #{limit}

